  window.EXTRA_READ_STORIES.push(...[{"id": "pt-manha", "title": "Manhã na cidade", "subtitle": "Morning in the city", "trail": "green-circle", "sentences": [{"foreign": "Bom dia.", "en": "Good morning."}, {"foreign": "Acabei de chegar.", "en": "I just arrived."}, {"foreign": "Está frio, mas o sol aparece.", "en": "It is cold, but the sun is out."}, {"foreign": "Vejo pessoas e ônibus em todo lugar.", "en": "I see people and buses everywhere."}, {"foreign": "Com licença, onde fica a estação?", "en": "Excuse me, where is the station?"}, {"foreign": "Siga em frente e depois à esquerda.", "en": "Go straight and then left."}, {"foreign": "Obrigado. Ainda estou aprendendo português.", "en": "Thank you. I am still learning Portuguese."}, {"foreign": "Sem problema. Boa sorte!", "en": "No problem. Good luck!"}, {"foreign": "Tchau!", "en": "Bye!"}], "glosses": {"aparece": "appears / is out", "em todo lugar": "everywhere"}, "categoryId": "pt"}, {"id": "pt-cafe", "title": "Um café, por favor", "subtitle": "Ordering coffee", "trail": "green-circle", "sentences": [{"foreign": "Olá! Um café, por favor.", "en": "Hi! One coffee, please."}, {"foreign": "Com leite ou sem?", "en": "With milk or without?"}, {"foreign": "Com um pouco de leite, por favor.", "en": "With a little milk, please."}, {"foreign": "Quer algo para comer também?", "en": "Would you like something to eat too?"}, {"foreign": "Um pão de queijo, por favor.", "en": "A cheese bread, please."}, {"foreign": "Dá cinco reais.", "en": "That comes to five reais."}, {"foreign": "Posso pagar no cartão?", "en": "Can I pay by card?"}, {"foreign": "Pode sim.", "en": "Yes, you can."}, {"foreign": "Obrigado. Tenha um bom dia!", "en": "Thanks. Have a good day!"}], "glosses": {"dá": "comes to / costs", "pão de queijo": "Brazilian cheese bread"}, "categoryId": "pt"}, {"id": "pt-trem", "title": "No trem", "subtitle": "On the train", "trail": "green-circle", "sentences": [{"foreign": "Esse trem vai para o centro?", "en": "Does this train go downtown?"}, {"foreign": "Sim, vai.", "en": "Yes, it does."}, {"foreign": "Onde compro a passagem?", "en": "Where do I buy the ticket?"}, {"foreign": "No aplicativo ou na máquina.", "en": "In the app or at the machine."}, {"foreign": "Uma passagem só de ida, por favor.", "en": "One one-way ticket, please."}, {"foreign": "Janela ou corredor?", "en": "Window or aisle?"}, {"foreign": "Janela, por favor. Demora quanto tempo?", "en": "Window, please. How long does it take?"}, {"foreign": "Umas duas horas.", "en": "About two hours."}, {"foreign": "Obrigado pela ajuda.", "en": "Thanks for the help."}], "glosses": {"passagem": "ticket", "corredor": "aisle"}, "categoryId": "pt"}, {"id": "pt-biblioteca", "title": "Na biblioteca", "subtitle": "At the library", "trail": "blue-square", "sentences": [{"foreign": "Oi, preciso de um lugar quieto para estudar.", "en": "Hi, I need a quiet place to study."}, {"foreign": "No segundo andar tem mesas livres.", "en": "On the second floor there are free tables."}, {"foreign": "Vocês ficam abertos até que horas?", "en": "Until what time are you open?"}, {"foreign": "Até as vinte e uma hoje.", "en": "Until nine p.m. today."}, {"foreign": "Posso pegar livros emprestados aqui?", "en": "Can I borrow books here?"}, {"foreign": "Sim, com a carteirinha da universidade.", "en": "Yes, with the university card."}, {"foreign": "Ótimo. Tenho prova na semana que vem.", "en": "Great. I have a test next week."}, {"foreign": "Boa sorte nos estudos!", "en": "Good luck with your studies!"}], "glosses": {"emprestados": "borrowed", "carteirinha": "ID card"}, "categoryId": "pt"}, {"id": "pt-mercado", "title": "No mercado", "subtitle": "At the market", "trail": "blue-square", "sentences": [{"foreign": "Quanto custa esse queijo?", "en": "How much is this cheese?"}, {"foreign": "Três reais cada um.", "en": "Three reais each."}, {"foreign": "Levo dois, por favor.", "en": "I'll take two, please."}, {"foreign": "Quer uma sacola?", "en": "Would you like a bag?"}, {"foreign": "Quero sim. E um pouco de fruta também.", "en": "Yes. And some fruit too."}, {"foreign": "Maçã ou laranja?", "en": "Apple or orange?"}, {"foreign": "Maçã, quatro unidades.", "en": "Apple, four of them."}, {"foreign": "Tudo junto dá dez reais.", "en": "All together that's ten reais."}, {"foreign": "Aqui está. Até logo!", "en": "Here you go. See you!"}], "glosses": {"unidades": "units / pieces", "sacola": "bag"}, "categoryId": "pt"}, {"id": "pt-amigos", "title": "Novos amigos", "subtitle": "New friends", "trail": "blue-square", "sentences": [{"foreign": "Oi, eu sou a Sam.", "en": "Hi, I'm Sam."}, {"foreign": "Prazer. Eu sou o Leo.", "en": "Nice to meet you. I'm Leo."}, {"foreign": "De onde você é?", "en": "Where are you from?"}, {"foreign": "Do Canadá, mas moro aqui agora.", "en": "From Canada, but I live here now."}, {"foreign": "O que você estuda?", "en": "What do you study?"}, {"foreign": "Computação. E você?", "en": "Computer science. And you?"}, {"foreign": "História. Café depois da aula?", "en": "History. Coffee after class?"}, {"foreign": "Bora! Até já.", "en": "Let's go! See you in a bit."}], "glosses": {"bora": "let's go (informal)", "até já": "see you soon"}, "categoryId": "pt"}, {"id": "pt-trabalho", "title": "Primeiro dia de trabalho", "subtitle": "First day at work", "trail": "black-diamond", "sentences": [{"foreign": "Bem-vinda ao time, Sam.", "en": "Welcome to the team, Sam."}, {"foreign": "Obrigada. Estou um pouco nervosa.", "en": "Thanks. I'm a bit nervous."}, {"foreign": "É normal. A gente começa às oito e meia.", "en": "That's normal. We start at half past eight."}, {"foreign": "Onde posso deixar minhas coisas?", "en": "Where can I leave my things?"}, {"foreign": "Aqui perto da janela é a sua mesa.", "en": "Here by the window is your desk."}, {"foreign": "Se tiver dúvida, é só perguntar.", "en": "If you have a question, just ask."}, {"foreign": "Entendi. Quem é meu supervisor?", "en": "Got it. Who is my supervisor?"}, {"foreign": "Sou eu por hoje. Vem, eu te mostro a cozinha.", "en": "That's me for today. Come, I'll show you the kitchen."}], "glosses": {"time": "team", "dúvida": "doubt / question"}, "categoryId": "pt"}, {"id": "pt-medico", "title": "No médico", "subtitle": "At the doctor's", "trail": "black-diamond", "sentences": [{"foreign": "O que está sentindo?", "en": "What are you feeling?"}, {"foreign": "Estou com dor de garganta há dois dias.", "en": "I've had a sore throat for two days."}, {"foreign": "Tem febre também?", "en": "Do you also have a fever?"}, {"foreign": "Um pouco, de manhã.", "en": "A little, in the morning."}, {"foreign": "Vou dar uma olhada. Abra a boca.", "en": "I'll take a look. Open your mouth."}, {"foreign": "Parece uma infecção leve.", "en": "It looks like a mild infection."}, {"foreign": "Preciso de antibiótico?", "en": "Do I need an antibiotic?"}, {"foreign": "Ainda não. Repouso, água e dipirona.", "en": "Not yet. Rest, water, and painkiller."}, {"foreign": "Obrigada, doutor.", "en": "Thank you, doctor."}], "glosses": {"garganta": "throat", "repouso": "rest"}, "categoryId": "pt"}, {"id": "pt-moradia", "title": "Procurando um quarto", "subtitle": "Looking for a room", "trail": "black-diamond", "sentences": [{"foreign": "Oi, liguei sobre o quarto do anúncio.", "en": "Hi, I called about the room in the ad."}, {"foreign": "Ainda está disponível. Quando pode ver?", "en": "It's still available. When can you see it?"}, {"foreign": "Hoje à tarde, por volta das três.", "en": "This afternoon, around three."}, {"foreign": "Perfeito. Fica no centro, no terceiro andar.", "en": "Perfect. It's downtown, on the third floor."}, {"foreign": "Tem elevador?", "en": "Is there an elevator?"}, {"foreign": "Não, só escada. O aluguel inclui internet.", "en": "No, only stairs. Rent includes internet."}, {"foreign": "E tem caução?", "en": "And is there a deposit?"}, {"foreign": "Sim, um mês adiantado. Até logo!", "en": "Yes, one month in advance. See you!"}], "glosses": {"anúncio": "listing / ad", "aluguel": "rent", "caução": "deposit"}, "categoryId": "pt"}, {"id": "pt-noticias", "title": "Greve no metrô", "subtitle": "Subway strike", "trail": "double-black-diamond", "sentences": [{"foreign": "Você viu a notícia?", "en": "Did you see the news?"}, {"foreign": "Não, o que aconteceu?", "en": "No, what happened?"}, {"foreign": "Amanhã tem greve no metrô.", "en": "Tomorrow there's a subway strike."}, {"foreign": "Então os trens não vão circular?", "en": "So the trains won't run?"}, {"foreign": "Muitos vão parar, principalmente de manhã.", "en": "Many will stop, especially in the morning."}, {"foreign": "Vou de bicicleta, mesmo com chuva.", "en": "I'll go by bike, even with rain."}, {"foreign": "Esperto. Ou você trabalha de casa?", "en": "Smart. Or are you working from home?"}, {"foreign": "Talvez. Ainda vou falar com o chefe.", "en": "Maybe. I'll still talk to the boss."}], "glosses": {"greve": "strike", "circular": "to run / circulate"}, "categoryId": "pt"}, {"id": "pt-debate", "title": "Um debate rápido", "subtitle": "A short debate", "trail": "double-black-diamond", "sentences": [{"foreign": "Eu acho transporte público muito importante.", "en": "I think public transport is very important."}, {"foreign": "Por quê?", "en": "Why?"}, {"foreign": "Porque nem todo mundo pode ter carro.", "en": "Because not everyone can have a car."}, {"foreign": "Mas ônibus estão sempre lotados e atrasados.", "en": "But buses are always crowded and late."}, {"foreign": "Se investirmos mais, melhora.", "en": "If we invest more, it improves."}, {"foreign": "A longo prazo, talvez. Agora custa caro.", "en": "In the long run, maybe. Right now it's expensive."}, {"foreign": "Verdade. Mesmo assim acho que vale a pena.", "en": "True. Even so I think it's worth it."}, {"foreign": "Vamos ler mais sobre isso antes de decidir.", "en": "Let's read more about it before deciding."}], "glosses": {"lotados": "crowded", "vale a pena": "is worth it"}, "categoryId": "pt"}, {"id": "pt-planos", "title": "Planos para o verão", "subtitle": "Summer plans", "trail": "double-black-diamond", "sentences": [{"foreign": "O que você vai fazer no verão?", "en": "What are you going to do in the summer?"}, {"foreign": "Quero viajar umas semanas, se der certo.", "en": "I want to travel a few weeks, if it works out."}, {"foreign": "Para onde?", "en": "Where to?"}, {"foreign": "Talvez para o Nordeste. E você?", "en": "Maybe to the Northeast. And you?"}, {"foreign": "Vou ficar e trabalhar horas extras.", "en": "I'll stay and work overtime."}, {"foreign": "Chato? Ou prático?", "en": "Boring? Or practical?"}, {"foreign": "Prático. Estou guardando dinheiro para o ano que vem.", "en": "Practical. I'm saving money for next year."}, {"foreign": "Se quiser ir depois, me avisa.", "en": "If you want to go later, let me know."}, {"foreign": "Combinado. Me mantém no loop.", "en": "Deal. Keep me in the loop."}], "glosses": {"der certo": "works out", "horas extras": "overtime", "combinado": "deal"}, "categoryId": "pt"}]);
